from itertools import cycle
from functools import lru_cache

#input_signal = "" *10000
input_signal = "03036732577212944063491565474664" *10000
offset = int(input_signal[:7])
base_pattern = [0, 1, 0, -1]

@lru_cache(maxsize=None)
def pattern_for_row(row):
  result = []
  for p in base_pattern:
    for _ in range(row):
      result.append(p)
  r = result[1:] + result[0:1]
  return r

for r in range(100):
  print(f"Round",r)
  next_phrase = "0" * offset
  # Each row calculates one digit in the final answer.  
  # Each digit always uses the same pattern.
  # We are only interested in the non-zero bits of the pattern
  # We can ignore any values to our left.  (We might need the preceeding one)
  for row in range(offset, len(input_signal)):
    next_phrase += (str(sum([int(a) for a in input_signal[row:]]))[-1])
  input_signal = next_phrase
print(next_phrase[offset:offset+8])
